import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuthStore } from '@/store/useAuthStore'
import { supabase } from '@/lib/supabase'
import { Header } from '@/components/Header'
import { BottomNav } from '@/components/BottomNav'
import { Button } from '@/components/AuthFormPrimitives'

// Profile mit Editor — Sprint 8.
// Edit: display_name, daily_goal_xp, avatar_emoji, reminder.
// Settings: Soft-Delete-Link.

const GOALS = [50, 100, 200, 400]
const AVATARS = ['🌺', '🩺', '🫀', '🧠', '👨‍⚕️', '👩‍⚕️', '🌱', '🔬', '💊']

type ProfileData = {
  display_name: string | null
  username: string | null
  avatar_emoji: string | null
  rank: string | null
  level: number | null
  current_streak: number | null
  longest_streak: number | null
  daily_goal_xp: number | null
  app_xp: Record<string, number> | null
  notifications_enabled: boolean | null
  reminder_time: string | null
}

export default function Profile() {
  const { user, signOut } = useAuthStore()
  const navigate = useNavigate()
  const [profile, setProfile] = useState<ProfileData | null>(null)
  const [editing, setEditing] = useState(false)
  const [draft, setDraft] = useState<Partial<ProfileData>>({})
  const [saving, setSaving] = useState(false)
  const [savedAt, setSavedAt] = useState<number | null>(null)

  useEffect(() => {
    if (!user) return
    void supabase
      .from('profiles')
      .select('display_name, username, avatar_emoji, rank, level, current_streak, longest_streak, daily_goal_xp, app_xp, notifications_enabled, reminder_time')
      .eq('id', user.id)
      .single()
      .then(({ data }) => {
        if (data) {
          const p = data as ProfileData
          setProfile(p)
          setDraft({
            display_name: p.display_name,
            avatar_emoji: p.avatar_emoji,
            daily_goal_xp: p.daily_goal_xp,
            notifications_enabled: p.notifications_enabled,
            reminder_time: p.reminder_time
          })
        }
      })
  }, [user])

  async function handleSave() {
    if (!user || !profile) return
    setSaving(true)
    await supabase
      .from('profiles')
      .update({
        display_name: draft.display_name?.toString().trim() || profile.display_name,
        avatar_emoji: draft.avatar_emoji ?? profile.avatar_emoji,
        daily_goal_xp: draft.daily_goal_xp ?? profile.daily_goal_xp,
        notifications_enabled: draft.notifications_enabled ?? false,
        reminder_time: draft.notifications_enabled ? draft.reminder_time : null
      })
      .eq('id', user.id)
    setProfile({ ...profile, ...(draft as ProfileData) })
    setEditing(false)
    setSaving(false)
    setSavedAt(Date.now())
    setTimeout(() => setSavedAt(null), 2000)
  }

  const viragXp = profile?.app_xp?.virag ?? 0

  return (
    <div style={{ minHeight: '100vh', background: 'var(--cream)', paddingBottom: 90 }}>
      <Header />
      <main className="app-container">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline' }}>
          <h1 className="app-name" style={{ color: 'var(--red)', margin: 0, fontSize: '1.45rem' }}>Profil 👤</h1>
          {!editing && profile && (
            <button
              onClick={() => setEditing(true)}
              style={{ background: 'none', border: '1.5px solid var(--green)', color: 'var(--green)', padding: '0.35rem 0.7rem', borderRadius: 8, fontFamily: 'inherit', fontSize: '0.78rem', fontWeight: 600, cursor: 'pointer' }}
            >
              ✏️ Bearbeiten
            </button>
          )}
        </div>

        {savedAt && (
          <div style={{ padding: '0.5rem 0.8rem', background: 'rgba(62,90,10,0.12)', border: '1.5px solid var(--green)', borderRadius: 8, color: 'var(--green)', fontSize: '0.85rem' }}>
            ✓ Gespeichert
          </div>
        )}

        {/* Header-Card */}
        <div style={{ background: 'var(--white)', border: '2px solid var(--red)', borderRadius: 14, padding: '1.5rem 1.25rem', boxShadow: 'var(--shadow-card)', display: 'flex', alignItems: 'center', gap: '1rem' }}>
          <div style={{ fontSize: '3rem' }}>{(editing ? draft.avatar_emoji : profile?.avatar_emoji) ?? '🌺'}</div>
          <div style={{ flex: 1 }}>
            <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '1.2rem', color: 'var(--red)' }}>
              {profile?.display_name ?? user?.email?.split('@')[0] ?? '…'}
            </div>
            <div style={{ fontSize: '0.85rem', opacity: 0.7, marginTop: 2 }}>
              {profile?.rank ?? 'Medikus I'} · Level {profile?.level ?? 1}
            </div>
            <div style={{ fontSize: '0.78rem', opacity: 0.55, marginTop: 2 }}>{user?.email}</div>
          </div>
        </div>

        {editing && (
          <div style={{ background: 'var(--white)', border: '2px solid var(--green)', borderRadius: 14, padding: '1.2rem', boxShadow: 'var(--shadow-card)', display: 'flex', flexDirection: 'column', gap: '1.2rem' }}>
            {/* Display Name */}
            <Field label="Anzeigename">
              <input
                type="text"
                value={draft.display_name ?? ''}
                onChange={(e) => setDraft({ ...draft, display_name: e.target.value })}
                style={inputStyle()}
              />
            </Field>

            {/* Avatar */}
            <Field label="Avatar">
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                {AVATARS.map((a) => (
                  <button
                    key={a}
                    onClick={() => setDraft({ ...draft, avatar_emoji: a })}
                    style={{
                      background: draft.avatar_emoji === a ? 'var(--cream)' : 'var(--white)',
                      border: `2px solid ${draft.avatar_emoji === a ? 'var(--red)' : 'rgba(0,0,0,0.1)'}`,
                      width: 44, height: 44, borderRadius: 10, cursor: 'pointer', fontSize: '1.5rem'
                    }}
                  >
                    {a}
                  </button>
                ))}
              </div>
            </Field>

            {/* Tagesziel */}
            <Field label="Tagesziel (XP)">
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                {GOALS.map((g) => (
                  <button
                    key={g}
                    onClick={() => setDraft({ ...draft, daily_goal_xp: g })}
                    style={{
                      padding: '0.5rem 0.9rem', borderRadius: 10, border: '2px solid var(--red)',
                      background: draft.daily_goal_xp === g ? 'var(--red)' : 'transparent',
                      color: draft.daily_goal_xp === g ? 'var(--cream)' : 'var(--red)',
                      fontFamily: 'inherit', fontWeight: 700, fontSize: '0.9rem', cursor: 'pointer', minWidth: 64
                    }}
                  >
                    {g}
                  </button>
                ))}
              </div>
            </Field>

            {/* Reminder */}
            <Field label="Tägliche Erinnerung">
              <label style={{ display: 'flex', alignItems: 'center', gap: 10, cursor: 'pointer' }}>
                <input
                  type="checkbox"
                  checked={!!draft.notifications_enabled}
                  onChange={(e) => setDraft({ ...draft, notifications_enabled: e.target.checked })}
                  style={{ width: 18, height: 18, accentColor: 'var(--red)' }}
                />
                <span style={{ fontSize: '0.9rem' }}>aktiv</span>
              </label>
              {draft.notifications_enabled && (
                <input
                  type="time"
                  value={draft.reminder_time ?? '19:00'}
                  onChange={(e) => setDraft({ ...draft, reminder_time: e.target.value })}
                  style={{ ...inputStyle(), marginTop: 8, maxWidth: 150 }}
                />
              )}
            </Field>

            {/* Save / Cancel */}
            <div style={{ display: 'flex', gap: 8 }}>
              <button onClick={handleSave} disabled={saving} style={{ flex: 1, background: 'var(--red)', color: 'var(--cream)', border: 'none', padding: '0.7rem', borderRadius: 10, fontFamily: 'inherit', fontWeight: 700, fontSize: '0.95rem', cursor: 'pointer', opacity: saving ? 0.5 : 1 }}>
                {saving ? 'Speichern…' : 'Speichern'}
              </button>
              <button onClick={() => setEditing(false)} disabled={saving} style={{ background: 'none', border: '2px solid rgba(0,0,0,0.15)', padding: '0.7rem 1rem', borderRadius: 10, fontFamily: 'inherit', fontWeight: 600, cursor: 'pointer' }}>
                Abbrechen
              </button>
            </div>
          </div>
        )}

        {/* KPI-Karten */}
        {!editing && (
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.7rem' }}>
            <InfoCard label="Virág-XP">{viragXp}</InfoCard>
            <InfoCard label="Tagesziel">{profile?.daily_goal_xp ?? 100} XP</InfoCard>
            <InfoCard label="Aktueller Streak">{profile?.current_streak ?? 0} Tage</InfoCard>
            <InfoCard label="Bestleistung">{profile?.longest_streak ?? 0} Tage</InfoCard>
          </div>
        )}

        {/* Account-Bereich */}
        {!editing && (
          <div style={{ marginTop: '0.5rem', display: 'flex', flexDirection: 'column', gap: 8 }}>
            <Button variant="ghost" onClick={signOut}>Abmelden</Button>
            <button
              onClick={() => navigate('/profile/delete-account')}
              style={{ background: 'none', border: 'none', padding: '0.5rem', color: 'var(--red)', fontSize: '0.78rem', cursor: 'pointer', textDecoration: 'underline', opacity: 0.7 }}
            >
              Account löschen
            </button>
          </div>
        )}
      </main>
      <BottomNav />
    </div>
  )
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div>
      <div style={{ fontSize: '0.78rem', fontWeight: 600, opacity: 0.7, marginBottom: 6, letterSpacing: '0.3px' }}>{label}</div>
      {children}
    </div>
  )
}

function inputStyle(): React.CSSProperties {
  return {
    padding: '0.6rem 0.85rem', fontSize: '0.95rem', border: '1.5px solid rgba(0,0,0,0.15)', borderRadius: 8,
    fontFamily: 'inherit', background: 'var(--white)', outline: 'none', width: '100%'
  }
}

function InfoCard({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div style={{ background: 'var(--white)', border: '2px solid var(--green)', borderRadius: 12, padding: '0.85rem 1rem', boxShadow: 'var(--shadow-card)' }}>
      <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '1.3rem', color: 'var(--red)' }}>{children}</div>
      <div style={{ fontSize: '0.75rem', opacity: 0.65, marginTop: 2 }}>{label}</div>
    </div>
  )
}
